  "membership.7375fdb4317b": { "zh": "一切完全定制，不限次数、不限条件、不限地域。黑卡独享超越极限", "en": "Fully customized — unlimited, unconditional, unrestricted worldwide. Ultimate exclusivity beyond limits" },
