  "partner-type-agent.b4": { "zh": "区域保护政策，保障代理权益", "en": "Regional protection policies to safeguard agency rights" },
  "partner-type-agent.faq0_a": { "zh": "我们欢迎具有高端客户资源、行业经验或销售能力的个人与机构。具体要求根据合作层级有所不同，区域总代理需具备团队管理能力和本地市场影响力。", "en": "We welcome individuals and organizations with high-end customer resources, industry experience, or sales capabilities. Specific requirements vary by partnership tier; Regional Master Agents need team management capabilities and local market influence." },
  "partner-type-agent.faq0_q": { "zh": "成为代理商需要什么条件？", "en": "What are the requirements to become an agent?" },
  "partner-type-agent.faq1_a": { "zh": "我们提供行业有竞争力的佣金结构，根据产品类型、订单规模与合作层级浮动，并设有阶梯式激励方案。详细政策将在签约前披露。", "en": "We offer industry-competitive commission structures that vary by product type, order size, and partnership tier, with tiered incentive programs. Detailed policies will be disclosed before signing." },
  "partner-type-agent.faq1_q": { "zh": "代理商的佣金政策是怎样的？", "en": "What is the agent commission policy?" },
  "partner-type-agent.faq2_a": { "zh": "是的。区域总代理享有指定区域的独家代理权保障。城市合作伙伴也享有对应城市的优先服务权，确保各层级代理的利益不受冲突。", "en": "Yes. Regional Master Agents enjoy exclusive agency rights within their designated territories. City Partners also have priority service rights in their corresponding cities, ensuring conflict-free interests across all agency tiers." },
  "partner-type-agent.faq2_q": { "zh": "有区域保护吗？", "en": "Is there regional protection?" },
