  "partner-type-art.650": { "zh": "常见问题", "en": "FAQ" },
  "partner-type-art.b0": { "zh": "全球顶级画廊与拍卖行直通渠道", "en": "Direct access to world-class galleries and auction houses" },
  "partner-type-art.b1": { "zh": "游艇空间专属艺术定制服务", "en": "Exclusive yacht space art customization service" },
  "partner-type-art.b2": { "zh": "藏品鉴赏与投资顾问", "en": "Collection appreciation and investment advisory" },
  "partner-type-art.b3": { "zh": "专业艺术品运输与保险方案", "en": "Professional art transportation and insurance solutions" },
  "partner-type-art.b4": { "zh": "艺术家驻船创作与VIP私享展览", "en": "Artist-in-residence creation and VIP private exhibitions" },
  "partner-type-art.faq0_a": { "zh": "我们采用专业的海洋级艺术品固定与温湿度控制系统，针对游艇振动、湿度、盐雾等特殊环境做全面防护，并由专业保险全程覆盖。", "en": "We employ professional marine-grade artwork mounting and climate control systems, providing comprehensive protection against yacht-specific challenges like vibration, humidity, and salt spray, with full professional insurance coverage." },
  "partner-type-art.faq0_q": { "zh": "艺术品在游艇上安全吗？", "en": "Is artwork safe on a yacht?" },
  "partner-type-art.faq1_a": { "zh": "视艺术家档期与作品复杂度而定，通常3-8个月。我们建议在游艇建造阶段即启动艺术方案策划，确保空间与作品的完美融合。", "en": "Depending on artist availability and artwork complexity, typically 3-8 months. We recommend initiating art planning during the yacht construction phase to ensure perfect spatial integration." },
  "partner-type-art.faq1_q": { "zh": "艺术品定制周期多长？", "en": "How long does custom artwork take?" },
  "partner-type-art.faq2_a": { "zh": "可以。奇幻假期会员可享受全球主要拍卖行的优先预展、代拍服务与专属VIP席位。", "en": "Yes. Fantastic Vacation members enjoy priority previews, proxy bidding, and exclusive VIP seats at major global auction houses." },
  "partner-type-art.faq2_q": { "zh": "可以参与拍卖吗？", "en": "Can I participate in auctions?" },
  "partner-type-art.step0_desc": { "zh": "了解客户艺术偏好、收藏目标与空间需求", "en": "Understand customer art preferences, collection goals, and spatial requirements" },
  "partner-type-art.step0_name": { "zh": "品味会诊", "en": "Taste Consultation" },
