  "partner-type-art.step1_name": { "zh": "方案策划", "en": "Solution Planning" },
  "partner-type-art.step2_desc": { "zh": "对接匹配的画廊、艺术家与拍卖行资源", "en": "Connect with matching galleries, artists, and auction houses" },
  "partner-type-art.step2_name": { "zh": "资源匹配", "en": "Resource Matching" },
  "partner-type-art.step3_desc": { "zh": "作品定制、运输、保险与安装全程管理", "en": "Full management of artwork customization, transportation, insurance, and installation" },
  "partner-type-art.step3_name": { "zh": "执行交付", "en": "Execution & Delivery" },
  "partner-type-art.step4_desc": { "zh": "定期策展、藏品增值服务与圈子社交", "en": "Regular curation, collection value-add services, and social networking" },
  "partner-type-art.step4_name": { "zh": "持续鉴赏", "en": "Ongoing Appreciation" },
  "partner-type-art.tier0_desc": { "zh": "珍藏顾问、优先预展、联合策展、私享拍卖", "en": "Collection advisory, priority preview, joint curation, private auctions" },
  "partner-type-art.tier0_name": { "zh": "全球艺术联盟", "en": "Global Art Alliance" },
  "partner-type-art.tier1_desc": { "zh": "作品推荐、租赁服务、小型展览", "en": "Artwork recommendation, leasing service, small exhibitions" },
  "partner-type-art.tier1_name": { "zh": "区域画廊伙伴", "en": "Regional Gallery Partner" },
  "partner-type-art.tier2_desc": { "zh": "定制创作、驻船项目、联名作品", "en": "Custom creation, onboard residency, co-branded artwork" },
  "partner-type-art.tier2_name": { "zh": "艺术家合作", "en": "Artist Collaboration" },
  "partner-type-association.600": { "zh": "奇幻假期与全球主要游艇行业协会、海事监管机构与标准制定组织紧密合作，确保我们的服务始终符合最高行业标准与合规要求。通过协会网络，我们为客户提供政策信息、行业洞察与合规保障。", "en": "Fantastic Vacation works closely with major global yacht industry associations, maritime regulatory bodies, and standards organizations to ensure our services always meet the highest industry standards and compliance requirements. Through our association network, we provide customers with policy information, industry insights, and compliance assurance." },
  "partner-type-association.601": { "zh": "合作概述", "en": "Partnership Overview" },
  "partner-type-association.610": { "zh": "合作优势", "en": "Partnership Benefits" },
