  "partner-type-association.b0": { "zh": "行业标准制定的参与权", "en": "Participation rights in industry standard setting" },
  "partner-type-association.b1": { "zh": "实时政策法规更新与合规指导", "en": "Real-time policy updates and compliance guidance" },
  "partner-type-association.b2": { "zh": "行业数据与市场报告共享", "en": "Industry data and market report sharing" },
  "partner-type-association.b3": { "zh": "国际海事展会与论坛参与权", "en": "International maritime exhibition and forum participation" },
  "partner-type-association.b4": { "zh": "行业人才认证与培训体系", "en": "Industry talent certification and training system" },
  "partner-type-association.faq0_a": { "zh": "协会成员身份确保我们的服务符合国际标准，客户可享受到受国际认可的合规服务、行业最新资讯以及更广泛的资源网络。", "en": "Association membership ensures our services meet international standards. Customers benefit from internationally recognized compliant services, the latest industry insights, and a broader resource network." },
  "partner-type-association.faq0_q": { "zh": "加入协会对客户有什么价值？", "en": "What value does association membership bring to customers?" },
  "partner-type-association.faq1_a": { "zh": "我们与地中海船坞协会、国际游艇协会（IYBA）、亚洲游艇行业协会等保持密切合作，并通过战略合作伙伴覆盖全球主要海事认证体系。", "en": "We maintain close cooperation with the Mediterranean Shipyard Association, International Yacht Brokers Association (IYBA), Asian Yacht Industry Association, and through strategic partners, cover major global maritime certification systems." },
  "partner-type-association.faq1_q": { "zh": "你们加入了哪些协会？", "en": "Which associations have you joined?" },
  "partner-type-association.faq2_a": { "zh": "通过协会获取最新的行业法规变化，我们能够在第一时间调整服务标准，确保客户的游艇运营始终合规，避免法律风险。", "en": "By accessing the latest regulatory changes through associations, we can adjust service standards promptly, ensuring customers' yacht operations remain compliant and avoiding legal risks." },
  "partner-type-association.faq2_q": { "zh": "行业协会如何帮助合规？", "en": "How do industry associations help with compliance?" },
  "partner-type-association.step0_desc": { "zh": "确定目标协会，提交合作意向与资质材料", "en": "Identify target associations, submit cooperation intent and qualification materials" },
