  "partner-type-association.step2_desc": { "zh": "激活会员权益，接入资源与服务体系", "en": "Activate membership benefits, connect to resources and service systems" },
  "partner-type-association.step2_name": { "zh": "权益激活", "en": "Benefits Activation" },
  "partner-type-association.step3_desc": { "zh": "参加委员会、工作组，参与行业建设", "en": "Join committees and working groups, participate in industry development" },
