  "partner-type-association.tier0_desc": { "zh": "联合研究、标准制定、行业白皮书发布", "en": "Joint research, standard setting, industry white paper publishing" },
  "partner-type-association.tier0_name": { "zh": "战略合作", "en": "Strategic Cooperation" },
  "partner-type-association.tier1_desc": { "zh": "行业数据、培训资源、展会参与", "en": "Industry data, training resources, exhibition participation" },
