  "partner-type-association.tier2_name": { "zh": "认证对接", "en": "Certification Alignment" },
  "partner-type-aviation.600": { "zh": "奇幻假期携手全球领先的私人航空服务商，为高净值客户打造海陆空无缝衔接的高端出行体验。从公务机包机、直升机接驳到停机坪协调，我们为游艇船东提供从家门口到甲板的全程尊享服务。", "en": "Fantastic Vacation partners with world-leading private aviation providers to create seamless sea-land-air premium travel experiences for high-net-worth clients. From business jet charters and helicopter transfers to helipad coordination, we offer yacht owners an exclusive door-to-deck journey." },
  "partner-type-aviation.601": { "zh": "合作概述", "en": "Partnership Overview" },
  "partner-type-aviation.610": { "zh": "合作优势", "en": "Partnership Benefits" },
