  "partner-type-aviation.650": { "zh": "常见问题", "en": "FAQ" },
  "partner-type-aviation.b0": { "zh": "全球公务机机队，覆盖6大洲航线", "en": "Global business jet fleet covering 6 continents" },
  "partner-type-aviation.b1": { "zh": "直升机海陆接驳，直飞游艇停机坪", "en": "Helicopter sea-land transfer, direct to yacht helipad" },
  "partner-type-aviation.b2": { "zh": "全球FBO与停机坪认证网络", "en": "Global FBO and helipad certification network" },
  "partner-type-aviation.b3": { "zh": "专属飞行管家一对一服务", "en": "Dedicated flight concierge one-on-one service" },
  "partner-type-aviation.b4": { "zh": "海空联运一体化行程管理", "en": "Integrated sea-air combined itinerary management" },
  "partner-type-aviation.faq0_a": { "zh": "主要面向拥有直升机停机坪的大型游艇客户（如君临系列、远征系列），同时也为所有会员提供目的地机场到码头的VIP接驳服务。", "en": "Primarily for large yacht customers with helipads (such as Sovereign and Expedition series), while also offering VIP airport-to-marina transfer services for all members." },
  "partner-type-aviation.faq0_q": { "zh": "航空服务适用于哪些游艇？", "en": "Which yachts are eligible for aviation services?" },
  "partner-type-aviation.faq1_a": { "zh": "标准预订需提前24小时，紧急需求可通过VIP通道在6-8小时内完成调度。覆盖区域内可最快4小时起飞。", "en": "Standard booking requires 24 hours' notice; urgent requests via VIP channels can be dispatched within 6-8 hours. In covered regions, the fastest takeoff is within 4 hours." },
  "partner-type-aviation.faq1_q": { "zh": "最快多久可以安排私人航班？", "en": "How quickly can a private flight be arranged?" },
  "partner-type-aviation.faq2_a": { "zh": "按飞行时长、机型、航线综合计费。会员享受专属价格体系，黑卡会员可享年度飞行额度礼遇。", "en": "Based on flight hours, aircraft type, and route. Members enjoy exclusive pricing, and Black Card members receive annual flight credit benefits." },
  "partner-type-aviation.faq2_q": { "zh": "航空服务如何收费？", "en": "How are aviation services charged?" },
  "partner-type-aviation.step0_desc": { "zh": "评估客户航线需求、机型偏好与安全标准", "en": "Assess customer route needs, aircraft preferences, and safety standards" },
  "partner-type-aviation.step0_name": { "zh": "需求评估", "en": "Needs Assessment" },
