  "partner-type-aviation.tier0_name": { "zh": "全球航空联盟", "en": "Global Aviation Alliance" },
  "partner-type-aviation.tier1_desc": { "zh": "区域航线机队、优先预订、标准服务", "en": "Regional route fleet, priority booking, standard services" },
  "partner-type-aviation.tier1_name": { "zh": "区域航空合作", "en": "Regional Aviation Partner" },
  "partner-type-aviation.tier2_desc": { "zh": "直升机接驳、机场VIP通道、行李转运", "en": "Helicopter transfer, airport VIP channels, luggage transfer" },
  "partner-type-aviation.tier2_name": { "zh": "接驳服务商", "en": "Transfer Service Provider" },
  "partner-type-brand.600": { "zh": "奇幻假期与全球高端品牌跨界联名，从奢华汽车、顶级腕表到珍稀酒品、高级时装——我们将不同领域的奢华基因注入游艇生活，为船东打造独一无二的品牌体验与限量定制珍品。", "en": "Fantastic Vacation co-brands with global luxury brands across categories — from luxury automobiles and premium watches to rare spirits and haute couture. We infuse the luxury DNA of diverse domains into yacht living, creating unique brand experiences and limited-edition treasures for yacht owners." },
  "partner-type-brand.601": { "zh": "合作概述", "en": "Partnership Overview" },
  "partner-type-brand.610": { "zh": "合作优势", "en": "Partnership Benefits" },
  "partner-type-brand.620": { "zh": "合作层级", "en": "Partnership Tiers" },
  "partner-type-brand.640": { "zh": "合作流程", "en": "Partnership Process" },
  "partner-type-brand.650": { "zh": "常见问题", "en": "FAQ" },
  "partner-type-brand.b0": { "zh": "全球高端品牌资源矩阵", "en": "Global luxury brand resource matrix" },
  "partner-type-brand.b1": { "zh": "限量联名定制，提升品牌价值", "en": "Limited-edition co-branded customization to enhance brand value" },
  "partner-type-brand.b2": { "zh": "联合品牌活动与VIP体验", "en": "Joint brand events and VIP experiences" },
  "partner-type-brand.b3": { "zh": "跨界营销与客户资源互通", "en": "Cross-border marketing and customer resource sharing" },
  "partner-type-brand.b4": { "zh": "品牌故事与内容共创", "en": "Brand storytelling and content co-creation" },
  "partner-type-brand.faq0_a": { "zh": "奇幻假期主要与高端生活方式品牌合作，包括但不限于：奢华汽车、顶级腕表、高级珠宝、珍稀酒品、高级时装、高端家居、科技数码等领域。核心标准是品牌调性与客群契合度。", "en": "Fantastic Vacation primarily partners with premium lifestyle brands, including but not limited to: luxury automobiles, premium watches, fine jewelry, rare spirits, haute couture, luxury home, and tech. The core criterion is brand identity and audience alignment." },
  "partner-type-brand.faq0_q": { "zh": "联名合作适合什么类型的品牌？", "en": "What type of brands are suitable for co-branding?" },
  "partner-type-brand.faq1_a": { "zh": "视产品复杂度而定，轻量级联名（如定制酒标、特别版礼盒）约2-3个月，深度联名（如游艇内饰联名设计）约6-12个月。", "en": "Depending on product complexity: lightweight co-branding (e.g., custom labels, special edition gift boxes) takes 2-3 months; deep co-branding (e.g., yacht interior co-design) takes 6-12 months." },
  "partner-type-brand.faq1_q": { "zh": "联名产品的开发周期多长？", "en": "How long is the co-branded product development cycle?" },
  "partner-type-brand.faq2_a": { "zh": "我们通过品牌曝光量、社交互动、新增客户、销售转化等多个维度建立评估体系，定期产出合作效果报告。", "en": "We establish an evaluation system across multiple dimensions including brand exposure, social engagement, new customer acquisition, and sales conversion, producing regular collaboration performance reports." },
  "partner-type-brand.faq2_q": { "zh": "如何衡量联名合作的效果？", "en": "How is co-branding effectiveness measured?" },
  "partner-type-brand.step0_desc": { "zh": "分析品牌调性、目标客群与合作契合度", "en": "Analyze brand identity, target audience, and collaboration fit" },
  "partner-type-brand.step0_name": { "zh": "品牌匹配", "en": "Brand Matching" },
  "partner-type-brand.step1_desc": { "zh": "设计联名方案、活动概念与传播策略", "en": "Design co-branding plan, event concept, and communication strategy" },
