  "partner-type-brand.step4_desc": { "zh": "全渠道推广、社群运营、口碑传播", "en": "Omni-channel promotion, community operations, word-of-mouth amplification" },
  "partner-type-brand.step4_name": { "zh": "传播放大", "en": "Amplification" },
  "partner-type-brand.tier0_desc": { "zh": "产品联名、内容共创、客户互通、品牌加持", "en": "Product co-branding, content co-creation, customer sharing, brand endorsement" },
  "partner-type-brand.tier0_name": { "zh": "深度联名", "en": "Deep Co-Branding" },
  "partner-type-brand.tier1_desc": { "zh": "联合发布会、体验活动、会员私享", "en": "Joint launches, experience events, member exclusives" },
  "partner-type-brand.tier1_name": { "zh": "主题活动", "en": "Themed Events" },
  "partner-type-brand.tier2_desc": { "zh": "场景植入、内容合作、渠道互通", "en": "Scene placement, content collaboration, channel sharing" },
  "partner-type-brand.tier2_name": { "zh": "品牌露出", "en": "Brand Exposure" },
  "partner-type-hotel.600": { "zh": "奇幻假期与全球奢华酒店与度假村建立深度合作，为游艇船东打造「海上+岸上」双栖奢享生活。从马尔代夫水上别墅到摩纳哥顶层套房，从私人沙滩晚宴到雪山温泉——每一次靠岸都是一段新的奢旅。", "en": "Fantastic Vacation partners deeply with global luxury hotels and resorts to create a dual-lifestyle of sea and shore luxury for yacht owners. From Maldives overwater villas to Monaco penthouse suites, from private beach dinners to mountain hot springs — every port call is a new luxury journey." },
  "partner-type-hotel.601": { "zh": "合作概述", "en": "Partnership Overview" },
  "partner-type-hotel.610": { "zh": "合作优势", "en": "Partnership Benefits" },
  "partner-type-hotel.620": { "zh": "合作层级", "en": "Partnership Tiers" },
