  "partner-type-hotel.650": { "zh": "常见问题", "en": "FAQ" },
  "partner-type-hotel.b0": { "zh": "全球200+奢华酒店与度假村网络", "en": "Global network of 200+ luxury hotels and resorts" },
  "partner-type-hotel.b1": { "zh": "会员互认，权益无缝对接", "en": "Mutual membership recognition with seamless benefit transfer" },
  "partner-type-hotel.b2": { "zh": "码头-酒店专属接驳服务", "en": "Dedicated marina-to-hotel transfer services" },
  "partner-type-hotel.b3": { "zh": "定制化海上+岸上联动套餐", "en": "Customized sea-and-shore package experiences" },
  "partner-type-hotel.b4": { "zh": "私人活动策划与执行", "en": "Private event planning and execution" },
  "partner-type-hotel.faq0_a": { "zh": "奇幻假期会员可直接通过专属客服或会员App预订合作酒店，自动享受升房、延迟退房、欢迎礼遇等权益。", "en": "Fantastic Vacation members can book partner hotels directly via dedicated concierge or the member app, automatically enjoying room upgrades, late checkout, welcome amenities, and more." },
  "partner-type-hotel.faq0_q": { "zh": "会员酒店权益如何享受？", "en": "How do I enjoy member hotel benefits?" },
  "partner-type-hotel.faq1_a": { "zh": "覆盖全球50+游艇热门目的地，包括摩纳哥、圣特罗佩、波多菲诺、迈阿密、迪拜、普吉岛、三亚等。", "en": "Covering 50+ popular yachting destinations worldwide, including Monaco, Saint-Tropez, Portofino, Miami, Dubai, Phuket, Sanya, and more." },
  "partner-type-hotel.faq1_q": { "zh": "酒店网络覆盖哪些目的地？", "en": "Which destinations does the hotel network cover?" },
  "partner-type-hotel.faq2_a": { "zh": "当然。我们提供私人晚宴、甲板派对、海上婚礼、商务接待等全方位定制服务，由专属活动策划团队执行。", "en": "Absolutely. We offer full-service customization for private dinners, deck parties, yacht weddings, corporate receptions, and more, executed by our dedicated event planning team." },
  "partner-type-hotel.faq2_q": { "zh": "可以定制私人活动吗？", "en": "Can private events be customized?" },
  "partner-type-hotel.step0_desc": { "zh": "根据客户航线与偏好，甄选匹配的奢华酒店", "en": "Select matching luxury hotels based on customer routes and preferences" },
  "partner-type-hotel.step0_name": { "zh": "酒店甄选", "en": "Hotel Selection" },
  "partner-type-hotel.step1_desc": { "zh": "实地考察评估硬件设施、服务水准与独特性", "en": "On-site evaluation of facilities, service standards, and uniqueness" },
  "partner-type-hotel.step1_name": { "zh": "体验评估", "en": "Experience Evaluation" },
  "partner-type-hotel.step2_desc": { "zh": "确定会员权益、价格体系与专属礼遇", "en": "Define membership benefits, pricing, and exclusive privileges" },
  "partner-type-hotel.step2_name": { "zh": "合约签订", "en": "Contract Signing" },
  "partner-type-hotel.step3_desc": { "zh": "会员体系互通，实现一键预订与权益核销", "en": "Membership system integration for one-click booking and benefit redemption" },
  "partner-type-hotel.step3_name": { "zh": "系统对接", "en": "System Integration" },
  "partner-type-hotel.step4_desc": { "zh": "定期推出联名套餐、主题活动与限时体验", "en": "Regular co-branded packages, themed events, and limited-time experiences" },
