  "partner-type-hotel.tier0_desc": { "zh": "会员权益互通、专属体验定制、联合品牌活动", "en": "Cross-member benefits, exclusive experience customization, co-branded events" },
  "partner-type-hotel.tier0_name": { "zh": "全球奢华联盟", "en": "Global Luxury Alliance" },
  "partner-type-hotel.tier1_desc": { "zh": "目的地推荐、优先预订、VIP礼遇", "en": "Destination recommendations, priority booking, VIP treatment" },
  "partner-type-hotel.tier1_name": { "zh": "区域精品伙伴", "en": "Regional Boutique Partner" },
  "partner-type-hotel.tier2_desc": { "zh": "协议价格、标准服务、品牌露出", "en": "Contracted rates, standard services, brand exposure" },
  "partner-type-hotel.tier2_name": { "zh": "甄选合作酒店", "en": "Select Partner Hotel" },
  "partner-type-marina.600": { "zh": "奇幻假期构建全球码头网络，覆盖地中海、加勒比海、东南亚、中东等热门航线区域。通过与世界顶级游艇码头合作，为船东提供专属泊位、VIP通道与一站式停靠服务，让每一次航行都无忧无虑。", "en": "Fantastic Vacation builds a global marina network covering the Mediterranean, Caribbean, Southeast Asia, Middle East, and other popular cruising regions. Through partnerships with world-class yacht marinas, we provide owners with dedicated berths, VIP access, and one-stop docking services for worry-free voyages." },
  "partner-type-marina.601": { "zh": "合作概述", "en": "Partnership Overview" },
  "partner-type-marina.610": { "zh": "合作优势", "en": "Partnership Benefits" },
  "partner-type-marina.620": { "zh": "合作层级", "en": "Partnership Tiers" },
  "partner-type-marina.640": { "zh": "合作流程", "en": "Partnership Process" },
  "partner-type-marina.650": { "zh": "常见问题", "en": "FAQ" },
  "partner-type-marina.b0": { "zh": "全球300+高端码头网络覆盖", "en": "Global network of 300+ premium marinas" },
  "partner-type-marina.b1": { "zh": "专属泊位预留与VIP优先通道", "en": "Dedicated berth reservation and VIP priority access" },
  "partner-type-marina.b2": { "zh": "码头服务一体化结算体系", "en": "Integrated marina service billing system" },
  "partner-type-marina.b3": { "zh": "跨国航线规划与地接服务", "en": "Cross-border route planning and local concierge services" },
  "partner-type-marina.b4": { "zh": "码头维修保养支援网络", "en": "Marina-based maintenance and repair support network" },
  "partner-type-marina.faq0_a": { "zh": "目前覆盖地中海（意大利、法国、西班牙、希腊、克罗地亚）、加勒比海、东南亚（泰国、马来西亚、新加坡、印尼）、中东（迪拜、阿布扎比）、澳洲等热门航线区域，网络持续扩展中。", "en": "Currently covering the Mediterranean (Italy, France, Spain, Greece, Croatia), Caribbean, Southeast Asia (Thailand, Malaysia, Singapore, Indonesia), Middle East (Dubai, Abu Dhabi), Australia, and other popular cruising regions. The network continues to expand." },
  "partner-type-marina.faq0_q": { "zh": "码头网络覆盖哪些区域？", "en": "Which regions does the marina network cover?" },
  "partner-type-marina.faq1_a": { "zh": "建议旺季（6-9月）提前3-4周预订，淡季提前1-2周即可。VIP客户可通过专属通道紧急预订，最快4小时内确认。", "en": "We recommend 3-4 weeks in advance during peak season (June-September), and 1-2 weeks during off-peak. VIP customers can make urgent bookings through dedicated channels, with the fastest confirmation within 4 hours." },
  "partner-type-marina.faq1_q": { "zh": "我需要提前多久预订码头泊位？", "en": "How far in advance should I book a marina berth?" },
  "partner-type-marina.faq2_a": { "zh": "费用根据码头等级、泊位尺寸、停靠时长综合计算。会员客户享受8-9.5折优惠，黑卡会员享受专属免费泊位配额。", "en": "Fees are calculated based on marina tier, berth size, and docking duration. Members enjoy 5-20% discounts, and Black Card members receive dedicated free berth quotas." },
  "partner-type-marina.faq2_q": { "zh": "码头费用如何计算？", "en": "How are marina fees calculated?" },
  "partner-type-marina.step0_desc": { "zh": "评估码头区位、设施、服务能力与安全标准", "en": "Evaluate marina location, facilities, service capability, and safety standards" },
  "partner-type-marina.step0_name": { "zh": "码头评估", "en": "Marina Assessment" },
