  "partner-type-marina.step2_desc": { "zh": "签署战略合作协议，确立服务标准与价格体系", "en": "Sign strategic cooperation agreement, establish service standards and pricing" },
  "partner-type-marina.step2_name": { "zh": "协议签署", "en": "Agreement Signing" },
  "partner-type-marina.step3_desc": { "zh": "泊位管理系统对接，实现一键预订", "en": "Integrate berth management systems for one-click booking" },
