  "partner-type-marina.step4_desc": { "zh": "定期服务评估，动态调整码头网络布局", "en": "Regular service evaluation, dynamic marina network optimization" },
  "partner-type-marina.step4_name": { "zh": "持续优化", "en": "Continuous Optimization" },
  "partner-type-marina.tier0_desc": { "zh": "专属泊位区、VIP码头管家、船上服务直达", "en": "Dedicated berth zone, VIP marina concierge, direct onboard service" },
  "partner-type-marina.tier0_name": { "zh": "旗舰码头", "en": "Flagship Marina" },
  "partner-type-marina.tier1_desc": { "zh": "优先泊位、标准补给服务、维修支援", "en": "Priority berthing, standard supply services, repair support" },
  "partner-type-marina.tier1_name": { "zh": "核心码头", "en": "Core Marina" },
  "partner-type-marina.tier2_desc": { "zh": "协议泊位、基础服务、信息联通", "en": "Contracted berthing, basic services, information connectivity" },
  "partner-type-marina.tier2_name": { "zh": "合作码头", "en": "Cooperative Marina" },
  "partner-type-service.600": { "zh": "奇幻假期整合游艇产业链上下游服务资源，从船舶保险、金融方案到船员培训、餐饮定制，我们构建一站式高端服务生态，让船东只需享受航行，其余交给我们。", "en": "Fantastic Vacation integrates upstream and downstream service resources across the yacht industry chain — from marine insurance and financial solutions to crew training and bespoke catering. We build a one-stop premium service ecosystem so owners can simply enjoy sailing while we handle the rest." },
  "partner-type-service.601": { "zh": "合作概述", "en": "Partnership Overview" },
  "partner-type-service.610": { "zh": "合作优势", "en": "Partnership Benefits" },
